using System.Collections.Generic;

namespace MarvelHeroes.DpsMeter.Services;

/// <summary>
/// Maps a boss <c>prototypeEnumIndex</c> (the same key used in <see cref="BossPrototypes.Indices"/>
/// and <see cref="BossPrototypes.MiniBossIndices"/>) to a human-readable display name --
/// e.g. <c>267u -> "Juggernaut"</c>.  Surfaced in the live overlay title during an active
/// boss fight, and baked into <c>DpsSnapshot.BossName</c> on auto-save so the fight history
/// shows which boss the run was against rather than just "Boss Fight".
///
/// <para>Generated by <c>scripts/GenerateBossNames.ps1</c> from the prototype paths in
/// <see cref="BossPrototypes"/>.  Re-run after regenerating BossPrototypes from a fresh
/// <c>OpenCalligraphy.AvatarEnumDumper</c> output.  Names are auto-derived from the path
/// basename with content-tag prefixes / chapter suffixes stripped -- for tricky cases edit
/// either this file directly or improve the cleanup heuristics in the generator.</para>
///
/// <para>Same dumper off-by-one caveat as <see cref="BossPrototypes.IsBoss"/>: indices &gt;=
/// 10000 may be one less on disk than what the live network sends, so callers should
/// probe both <c>idx</c> and <c>idx - 1</c> when resolving.  <see cref="Get"/> does this for you.</para>
/// </summary>
internal static class BossNames
{
    private const uint DumperOffByOneThreshold = 10000u;

    /// <summary>Returns the display name for <paramref name="prototypeEnumIndex"/>, or
    /// <c>null</c> when the index is unmapped.  Applies the same off-by-one workaround
    /// for indices &gt;= <see cref="DumperOffByOneThreshold"/> that <see cref="BossPrototypes.IsBoss"/>
    /// uses, so callers don't need to special-case the high-index range.</summary>
    public static string? Get(uint prototypeEnumIndex)
    {
        if (s_names.TryGetValue(prototypeEnumIndex, out var n)) return n;
        if (prototypeEnumIndex >= DumperOffByOneThreshold
            && s_names.TryGetValue(prototypeEnumIndex - 1u, out var n2)) return n2;
        return null;
    }

